import { createNavigation } from "next-intl/navigation";
import { routing } from "./routing";

/**
 * Wrappers de navigation conscients de la locale.
 *
 * Utiliser CES `Link`, `usePathname`, `useRouter`, `redirect` à la place
 * de ceux de `next/link` / `next/navigation` dans tout le "chrome"
 * (NavBar, Footer, Breadcrumbs, sélecteur de langue) :
 *
 *   • <Link href="/blog"> génère "/blog" en FR et "/en/blog" en EN automatiquement
 *   • usePathname() renvoie le chemin SANS le préfixe de locale
 *     → les comparaisons existantes (pathname.startsWith("/blog")) restent valides
 *       quelle que soit la langue.
 */
export const { Link, redirect, usePathname, useRouter, getPathname } =
  createNavigation(routing);
