import { defineRouting } from "next-intl/routing";

/**
 * Configuration i18n centrale.
 *
 * - `defaultLocale: "fr"` + `localePrefix: "as-needed"` :
 *     • le français est servi à la RACINE, sans préfixe   → /, /blog, /planetes/...
 *     • l'anglais et l'espagnol sont préfixés             → /en, /en/blog, /es, /es/...
 *   C'est exactement le schéma d'URL demandé.
 *
 * - `localeDetection: false` :
 *     on NE redirige PAS automatiquement selon l'Accept-Language du navigateur.
 *     Un visiteur qui arrive sur "/" reste en français (la home canonique du site).
 *     Le changement de langue se fait via le sélecteur. Évite les redirections
 *     surprises et les soucis de cache/SEO.
 */
export const routing = defineRouting({
  locales: ["fr", "en", "es"],
  defaultLocale: "fr",
  localePrefix: "as-needed",
  localeDetection: false,
});

export type Locale = (typeof routing.locales)[number];
